/*
 * 无头思维链提取 + Reasoning 面板美化（iframe 脚本版 / 纯 JS）
 * 规则：提取 reasoning，并把命中的 think 段从正文移除
 * 当前主题：极致日系极简（无标题单图标、丝滑交互动画、明朝体排版）
 */

(function () {
  const DEBUG = true;
  const SCRIPT_ID = typeof getScriptId === 'function' ? getScriptId() : 'reasoning_regex_styler';
  const STYLE_ID = `reasoning-style-${SCRIPT_ID}`;

  // 1. 配置注入：通过获取酒馆 Context 强行修改原生解析器配置
  function injectConfig() {
    const context = getST()?.getContext?.();
    const config = context?.powerUserSettings?.reasoning;
    if (config) {
      config.auto_parse = true;
      config.prefix = '<think>';
      config.suffix = '</think>';
      log('Config injected to ST via Context API');
    } else {
      log('Failed to inject config: Context or powerUserSettings not found');
    }
  }

  function getReasoningConfig() {
    const context = getST()?.getContext?.();
    const config = context?.powerUserSettings?.reasoning;
    if (config) {
      return {
        prefix: config.prefix || '-',
        suffix: config.suffix || '</think>',
        auto_expand: config.auto_expand
      };
    }
    return { prefix: '-', suffix: '</think>', auto_expand: true };
  }

  const REASONING_CSS = String.raw`
:root,
#chat {
    --qqz-accent: var(--theme-color-1, var(--SmartThemeQuoteColor));
    --qqz-accent-2: var(--theme-color-2, var(--SmartThemeUnderlineColor));
    --qqz-text-main: var(--text-color-main, #E2E8F0);
    --qqz-text-sec: var(--text-color-sec, #94A3B8);
}

/* 1. 主窗口 <details> - 彻底隐形，去容器化 */
.mes_reasoning_details {
    margin: 16px 0 !important;
    width: 100% !important;
    background: transparent !important;
    border: none !important;
    box-shadow: none !important;
}

/* 2. 顶部 <summary> - 仅作为图标容器，彻底抛弃文本 */
.mes_reasoning_summary {
    margin: 0 !important;
    padding: 8px 0 !important;
    background: transparent !important;
    border: none !important;
    cursor: pointer !important;
    display: flex !important;
    align-items: center !important;
    outline: none !important;
    list-style: none !important;
}
.mes_reasoning_summary::-webkit-details-marker { display: none !important; }

/* 3. 头部布局：实现单行左右对齐，一左（标题）一右（动作） */
.mes_reasoning_header_block {
    display: flex !important;
    flex-direction: row !important;
    flex-wrap: nowrap !important;
    align-items: center !important;
    justify-content: space-between !important; /* 核心：左右对齐 */
    background: transparent !important;
}

.mes_reasoning_header {
    display: flex !important;
    align-items: center !important;
    flex-shrink: 1 !important; /* 允许标题在极窄屏下收缩 */
    min-width: 0 !important;
}

/* 核心！彻底隐藏原生图标与多余元素，但保留原生标题用于展示动态小标题 */
.mes_reasoning_header .thinking-icon,
.mes_reasoning_header .icon-svg,
.mes_reasoning_arrow {
    display: none !important;
}

/* 4. 极致小标题样式：支持流式动态效果 */
.mes_reasoning_header_title {
    display: block !important;
    font-family: "Noto Serif SC", "Source Han Serif SC", serif !important;
    font-size: 0 !important; /* 【核心】隐藏原生文本（包括那六个点） */
    color: #94A3B8 !important;
    font-weight: 400 !important;
    transition: all 0.6s cubic-bezier(0.23, 1, 0.32, 1) !important;
    margin-left: 8px !important;
    background: transparent !important;
    position: relative !important;
}

/* 【生成期间】：流光呼吸效果 (作用于 ::before 重塑的文字) */
.mes[data-reasoning-state="thinking"] .mes_reasoning_header_title::before {
    content: attr(data-custom-title) !important;
    font-size: 0.85rem !important;
    color: #FFFFFF !important;
    mask-image: linear-gradient(90deg, rgba(255,255,255,0.4) 25%, #FFFFFF 50%, rgba(255,255,255,0.4) 75%);
    -webkit-mask-image: linear-gradient(90deg, rgba(255,255,255,0.4) 25%, #FFFFFF 50%, rgba(255,255,255,0.4) 75%);
    mask-size: 200% 100%;
    -webkit-mask-size: 200% 100%;
    animation: qqz-mask-shimmer 2s infinite linear !important;
}

/* 【已完成状态】：恢复静态标题 */
.mes[data-reasoning-state="done"] .mes_reasoning_header_title::before {
    content: attr(data-custom-title) !important;
    font-size: 0.85rem !important;
    color: #94A3B8 !important;
    opacity: 0.7 !important;
    animation: none !important;
}

.mes[data-reasoning-state="done"] .mes_reasoning_header_title::after {
    content: "" !important;
    animation: none !important;
    width: 0 !important;
}

/* 标题可视区：单行截断 */
.mes_reasoning_header_title::before {
    display: inline-block !important;
    max-width: min(56vw, 720px) !important;
    white-space: nowrap !important;
    overflow: hidden !important;
    text-overflow: clip !important;
    vertical-align: bottom !important;
}

/* 【生成期间】：固定省略号（不做动画） */
.mes[data-reasoning-state="thinking"] .mes_reasoning_header_title::after {
    content: "..." !important;
    font-size: 0.85rem !important;
    display: inline-block !important;
    vertical-align: bottom !important;
    margin-left: 1px !important;
    color: #94A3B8 !important;
    animation: none !important;
}

@keyframes qqz-mask-shimmer {
    0% { mask-position: 100% 0; -webkit-mask-position: 100% 0; }
    100% { mask-position: -100% 0; -webkit-mask-position: -100% 0; }
}

@keyframes qqz-title-glow {
    0%, 100% { opacity: 0.92; }
    50% { opacity: 1; }
}

/* 确保 Header 本身无背景 */
.mes_reasoning_header {
    background: transparent !important;
    border: none !important;
    box-shadow: none !important;
}

/* 标题辉光 */
.mes[data-reasoning-state="thinking"] .mes_reasoning_header_title::before {
    text-shadow: 0 0 10px rgba(255,255,255,0.38), 0 0 20px rgba(226,232,240,0.25) !important;
    animation: qqz-mask-shimmer 2s infinite linear, qqz-title-glow 2.2s ease-in-out infinite !important;
}

.mes[data-reasoning-state="done"] .mes_reasoning_header_title::before {
    text-shadow: 0 0 8px rgba(203,213,225,0.28) !important;
}

/* 标题切换时的丝滑动画：微小位移 + 模糊淡入 */
.mes_reasoning_header_title[data-animating="true"] {
    opacity: 0 !important;
    transform: translateX(10px) !important;
    filter: blur(4px) !important;
}

/* 4. 极致动画图标 (代替标题成为视觉锚点) */
.mes_reasoning_header::before {
    content: "" !important;
    display: block !important;
    width: 12px !important;
    height: 12px !important;
    box-sizing: border-box !important;
    border: 2px solid #94A3B8 !important; /* 暗银灰色边框 */
    border-radius: 2px !important;
    transition: all 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275) !important;
    margin-left: 2px !important; /* 微调以对齐下方的参考线 */
}

/* 【生成期间】：律动变换 (方阵 -> 柔和光晕圆 -> 旋转) */
.mes_reasoning_details:not([data-state="done"]) .mes_reasoning_header::before {
    border-color: #E2E8F0 !important;
    animation: pure-shape-shift 2.5s infinite cubic-bezier(0.65, 0, 0.35, 1);
}

@keyframes pure-shape-shift {
    0% { transform: rotate(0deg) scale(0.8); border-radius: 2px; }
    50% {
        transform: rotate(180deg) scale(1.3);
        border-radius: 50%;
        border-width: 1px;
        box-shadow: 0 0 12px rgba(226, 232, 240, 0.5);
        background-color: rgba(226, 232, 240, 0.1);
    }
    100% { transform: rotate(360deg) scale(0.8); border-radius: 2px; }
}

/* 【生成完毕】：静谧收敛为小菱形 */
.mes_reasoning_details[data-state="done"] .mes_reasoning_header::before {
    border-color: transparent !important;
    background-color: #64748B !important;
    transform: rotate(45deg) scale(0.7) !important;
}

/* Hover 交互：鼠标移上去时光芒点亮并旋转 */
.mes_reasoning_summary:hover .mes_reasoning_header::before {
    background-color: #E2E8F0 !important;
    transform: rotate(135deg) scale(0.9) !important;
    box-shadow: 0 0 12px rgba(255, 255, 255, 0.4) !important;
}

/* 5. 动作按钮组：优雅的滑入出场动画，确保在单行最右侧 */
.mes_reasoning_actions {
    display: flex !important;
    flex-direction: row !important;
    flex-wrap: nowrap !important;
    gap: 16px !important;
    width: auto !important;     /* 强制瘦身，防止占整行 */
    flex: none !important;      /* 禁止拉伸 */
    margin-left: auto !important; /* 精准靠右 */
    opacity: 0 !important;      /* 默认完全隐藏 */
    transform: translateX(15px) !important; /* 改为向右偏移，滑入更自然 */
    transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1) !important;
    pointer-events: none !important;
    background: transparent !important;
}

/* 鼠标悬浮在 summary 上时，按钮平滑浮现 */
.mes_reasoning_summary:hover .mes_reasoning_actions {
    opacity: 1 !important;
    transform: translateX(0) !important;
    pointer-events: auto !important;
}

.mes_reasoning_actions button {
    color: #94A3B8 !important;
    background: transparent !important;
    border: none !important;
    opacity: 0.5 !important;
    transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1) !important;
    font-size: 0.9rem !important;
    cursor: pointer !important;
    padding: 4px !important;
}

/* 单个按钮的 Hover 反馈：放大、上浮、发光 */
.mes_reasoning_actions button:hover {
    opacity: 1 !important;
    color: #E2E8F0 !important;
    transform: scale(1.2) translateY(-2px) !important;
    text-shadow: 0 0 8px rgba(226, 232, 240, 0.6) !important;
}

/* 6. 推演内容文本区 - 纯粹的日系平面排版与充裕的右侧留白 */
.mes_reasoning {
    margin: 8px 0 16px 7px !important; /* 左侧 margin 为 7px，精准对齐图标圆心 */
    padding: 4px 40px 12px 24px !important; /* 核心修复！右侧 40px Padding，彻底避免文字挤压滚动条 */
    border-left: 0px solid rgba(255, 255, 255, 0.1) !important; /* 删除原生的边线 */

    color: #CBD5E1 !important;
    font-family: "Noto Serif SC", "Source Han Serif SC", "STSong", "SimSun", serif !important; /* 优雅的日式明朝体 */
    font-size: 0.95em !important;
    line-height: 2.2 !important;
    letter-spacing: 1px !important;

    background: transparent !important;
    max-height: 400px;
    overflow-y: auto;
    text-align: justify !important;
    scrollbar-gutter: stable !important; /* 防止滚动条出现时文字跳动 */
}

/* ★ 极致细节：展开时的下落淡入动画 ★ */
.mes_reasoning_details[open] .mes_reasoning {
    animation: smooth-reveal 0.5s cubic-bezier(0.16, 1, 0.3, 1) forwards !important;
    transform-origin: top !important;
}

@keyframes smooth-reveal {
    0% { opacity: 0; transform: translateY(-12px); filter: blur(2px); }
    100% { opacity: 1; transform: translateY(0); filter: blur(0); }
}

/* 7. Markdown 列表修复与空间优化 */
.mes_reasoning ul,
.mes_reasoning ol {
    padding-left: 1.8em !important;
    margin-top: 0.8em !important;
    margin-bottom: 0.8em !important;
}
.mes_reasoning li { margin-bottom: 0.6em !important; }
.mes_reasoning p { margin-top: 0.8em !important; margin-bottom: 0.8em !important; }
.mes_reasoning > *:first-child { margin-top: 0 !important; }
.mes_reasoning > *:last-child { margin-bottom: 0 !important; }

/* 9. 不再物理隐藏正文，避免在状态误判或边界流式时出现“正文被吞” */
`;

  function log(...args) {
    if (!DEBUG) return;
    console.log('[ReasoningRegexStyler]', ...args);
  }

  function getTopDocument() {
    try {
      return window.top?.document || document;
    } catch {
      return document;
    }
  }

  function getST() {
    if (typeof SillyTavern !== 'undefined') return SillyTavern;
    return null;
  }

  function getChatArray() {
    const st = getST();
    if (st && Array.isArray(st.chat)) return st.chat;
    if (Array.isArray(window.chat)) return window.chat;
    return null;
  }

  function updateBlock(messageId, message) {
    const st = getST();
    if (st && typeof st.updateMessageBlock === 'function') {
      st.updateMessageBlock(messageId, message);
      return;
    }
    if (typeof window.updateMessageBlock === 'function') {
      window.updateMessageBlock(messageId, message);
    }
  }

  function injectStyleOnce(doc) {
    if (!doc || !doc.head) return;
    let style = doc.getElementById(STYLE_ID);
    if (!style) {
      style = doc.createElement('style');
      style.id = STYLE_ID;
      doc.head.appendChild(style);
      log('style created', { inTop: doc === getTopDocument() });
    }
    style.textContent = REASONING_CSS;
  }

  function injectStyle() {
    injectStyleOnce(document);
    injectStyleOnce(getTopDocument());
    log('style injected', { cssLength: REASONING_CSS.length });
  }

  function removeStyle() {
    for (const doc of [document, getTopDocument()]) {
      const style = doc?.getElementById?.(STYLE_ID);
      if (style) style.remove();
    }
    log('style removed');
  }

  /**
   * 核心：流式兼容的解析逻辑 (无头优先)
   */
  function extractReasoningAndClean(text, isStreaming) {
    if (typeof text !== 'string') return null;
    const { prefix, suffix } = getReasoningConfig();

    // 1. 如果包含闭合标签
    if (text.includes(suffix)) {
      const parts = text.split(suffix);
      let reasoningPart = parts[0];
      const cleaned = parts.slice(1).join(suffix).trim();

      // 如果有前缀则从前缀后开始截取
      if (reasoningPart.includes(prefix)) {
        reasoningPart = reasoningPart.split(prefix)[1];
      }

      const title = extractLatestHeaderByPriority(reasoningPart);
      return { reasoning: reasoningPart.trim(), cleaned, state: 'done', title };
    }

    // 2. 流式状态下，没看到闭合标签，则全部内容视为思维链
    if (isStreaming && text.length > 0) {
      let reasoning = text;
      // 如果有前缀则去掉前缀显示
      if (text.startsWith(prefix)) {
        reasoning = text.slice(prefix.length);
      }
      const title = extractLatestHeaderByPriority(reasoning);
      return { reasoning: reasoning.trim(), cleaned: '', state: 'thinking', title };
    }

    // 3. 非流式但有前缀的情况
    if (text.startsWith(prefix)) {
      const reasoning = text.slice(prefix.length).trim();
      const title = extractLatestHeaderByPriority(reasoning);
      return { reasoning, cleaned: '', state: 'thinking', title };
    }

    return null;
  }

  function normalizeHeaderText(str) {
    return String(str || '')
      .replace(/\s+/g, ' ')
      .replace(/[\u200B-\u200D\uFEFF]/g, '')
      .trim();
  }

  function findMessageDom(messageId) {
    const selector = `#chat [mesid="${messageId}"]`;
    const inFrame = document.querySelector(selector);
    if (inFrame) return inFrame;
    const topDoc = getTopDocument();
    return topDoc?.querySelector?.(selector) || null;
  }

  function resolveDisplayTitle(state, rawTitle) {
    const trimmed = normalizeHeaderText(rawTitle);
    if (state === 'done') return '思考结束';
    if (state === 'thinking') return trimmed || '思考中';
    return '';
  }

  function clipTitle(title, maxLen = 42) {
    const t = normalizeHeaderText(title);
    if (!t) return '';
    return t.length > maxLen ? t.slice(0, maxLen) : t;
  }

  function extractLatestHeaderByPriority(text) {
    const src = String(text || '');
    if (!src) return '';

    let best = null;

    const pick = (priority, index, rawTitle) => {
      const title = normalizeHeaderText(rawTitle);
      if (!title || /^[`~!@#$%^&*()_+\-=\[\]{};:'",.<>/?|\\]+$/.test(title)) return;

      if (!best || priority > best.priority || (priority === best.priority && index > best.index)) {
        best = { priority, index, title };
      }
    };

    // 优先级 3: # 标题 / ## 标题
    {
      const re = /^(#{1,2})\s+(.+)$/gm;
      let m;
      while ((m = re.exec(src)) !== null) {
        pick(3, m.index, m[2]);
      }
    }

    // 优先级 2: **标题**（行级）
    {
      const re = /(?:^|\n)\s*\*\*([^*\n][^*\n]*?)\*\*\s*(?=\n|$)/g;
      let m;
      while ((m = re.exec(src)) !== null) {
        pick(2, m.index, m[1]);
      }
    }

    // 优先级 1: - 标题 / • 标题
    {
      const re = /^\s*(?:-|•)\s+(.+)$/gm;
      let m;
      while ((m = re.exec(src)) !== null) {
        pick(1, m.index, m[1]);
      }
    }

    return best?.title || '';
  }

  function applyReasoningToMessage(messageId) {
    const id = Number(messageId);
    if (!Number.isInteger(id) || id < 0) return;

    const chat = getChatArray();
    if (!chat) return;

    const message = chat[id];
    if (!message || message.is_user) return;

    const isStreaming = message.swipe_id === undefined && message.gen_started && !message.extra?.reasoning_duration;

    if (message.extra?.reasoning) {
      const nativeState = message.extra?.reasoning_state;
      const state = nativeState === 'thinking' || nativeState === 'done'
        ? nativeState
        : (isStreaming ? 'thinking' : 'done');

      const { suffix } = getReasoningConfig();
      if (message.mes.includes(suffix)) {
        message.mes = message.mes.split(suffix).slice(1).join(suffix).trim();
        updateBlock(id, message);
      }

      // 只从 reasoning 区块提取标题，避免在正文阶段误抓正文首行
      const titleSource = String(message.extra?.reasoning || '');
      const extracted = extractLatestHeaderByPriority(titleSource);
      const title = clipTitle(resolveDisplayTitle(state, extracted));
      if (message.extra.reasoning_header_title !== title) {
        message.extra.reasoning_header_title = title;
      }

      updateReasoningUIState(id, state, title);
      return;
    }

    const parsed = extractReasoningAndClean(String(message.mes ?? ''), isStreaming);
    if (!parsed) {
      updateReasoningUIState(id, 'none');
      return;
    }

    message.extra = (message.extra && typeof message.extra === 'object') ? message.extra : {};
    message.extra.reasoning = parsed.reasoning;
    message.extra.reasoning_type = 'parsed';
    message.extra.reasoning_state = parsed.state;
    message.mes = parsed.cleaned;

    const title = clipTitle(resolveDisplayTitle(parsed.state, parsed.title));
    message.extra.reasoning_header_title = title;

    updateBlock(id, message);
    updateReasoningUIState(id, parsed.state, title);
  }

  /**
   * 强制同步 DOM 状态属性
   */
  function updateReasoningUIState(messageId, state, title) {
    requestAnimationFrame(() => {
      const messageDom = findMessageDom(messageId);
      if (!messageDom) return;

      // 【核心】给根节点挂载状态，通过 CSS 物理遮断正文渲染
      if (state === 'thinking') {
        messageDom.setAttribute('data-reasoning-state', 'thinking');
        messageDom.setAttribute('data-is-thinking', 'true');
      } else if (state === 'done') {
        messageDom.setAttribute('data-reasoning-state', 'done');
        messageDom.removeAttribute('data-is-thinking');
      } else {
        messageDom.removeAttribute('data-reasoning-state');
        messageDom.removeAttribute('data-is-thinking');
      }

      const mesDetails = messageDom.querySelector('.mes_reasoning_details');

      if (mesDetails) {
        if (mesDetails.getAttribute('data-state') !== state) {
          mesDetails.setAttribute('data-state', state);
        }
        const config = getReasoningConfig();
        if (state === 'thinking' && config.auto_expand) {
          if (!mesDetails.open) mesDetails.open = true;
        }
      }

      const mesTitle = messageDom.querySelector('.mes_reasoning_header_title');
      if (mesTitle) {
        const finalTitle = clipTitle(resolveDisplayTitle(state, title));
        const prevTitle = mesTitle.getAttribute('data-custom-title') || '';

        if (finalTitle) {
          if (prevTitle !== finalTitle) {
            mesTitle.setAttribute('data-animating', 'true');
            requestAnimationFrame(() => {
              mesTitle.setAttribute('data-custom-title', finalTitle);
              setTimeout(() => mesTitle.removeAttribute('data-animating'), 260);
            });
          }
        } else {
          mesTitle.removeAttribute('data-custom-title');
          mesTitle.removeAttribute('data-animating');
        }
      }
    });
  }

  function applyReasoningToAllMessages() {
    const chat = getChatArray();
    if (!chat) return;
    for (let i = 0; i < chat.length; i++) applyReasoningToMessage(i);
  }

  let streamTickRaf = 0;

  function scheduleApplyLatestAssistantMessage() {
    if (streamTickRaf) return;
    streamTickRaf = requestAnimationFrame(() => {
      streamTickRaf = 0;
      const chat = getChatArray();
      if (!chat || !chat.length) return;

      for (let i = chat.length - 1; i >= 0; i--) {
        const msg = chat[i];
        if (msg && !msg.is_user) {
          applyReasoningToMessage(i);
          break;
        }
      }
    });
  }

  function bindEvents() {
    if (typeof eventOn === 'function' && typeof tavern_events !== 'undefined') {
      eventOn(tavern_events.MESSAGE_UPDATED, (messageId) => {
        applyReasoningToMessage(messageId);
      });

      eventOn(tavern_events.MESSAGE_RECEIVED, (messageId) => {
        applyReasoningToMessage(messageId);
      });

      eventOn(tavern_events.CHAT_CHANGED, () => {
        injectConfig(); // 切换聊天时再次确保配置注入
        setTimeout(applyReasoningToAllMessages, 50);
      });

      eventOn(tavern_events.CHARACTER_MESSAGE_RENDERED, (messageId) => {
        applyReasoningToMessage(messageId);
      });

      // STREAM_TOKEN_RECEIVED 事件参数是 token 文本，不是 messageId
      eventOn(tavern_events.STREAM_TOKEN_RECEIVED, () => {
        scheduleApplyLatestAssistantMessage();
      });
    } else {
      log('eventOn/tavern_events not available');
    }
  }

  function init() {
    injectConfig();
    injectStyle();
